"use client";

// Daily / weekly / monthly / yearly predictions generated by the offline
// engine, plus an optional AI Insight (limit-gated, cost-visible).

import { use, useCallback, useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { useKundli } from "@/lib/useKundli";
import { useI18n } from "@/lib/i18n";
import { AppShell } from "@/components/AppShell";
import { ProfileTheme } from "@/components/ProfileTheme";
import {
  dailyPrediction,
  weeklyPrediction,
  monthlyPrediction,
  yearlyPrediction,
  type Prediction,
} from "@/lib/interpret/predictions";
import {
  getAiConfig,
  getUsageSummary,
  callAi,
  aiAvailable,
  fmtCost,
  GEMINI_FREE_RPD,
  type AiConfig,
  type UsageSummary,
} from "@/lib/aiClient";
import { fmtDate } from "@/lib/format";

type Period = "daily" | "weekly" | "monthly" | "yearly";

export default function PredictionsPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const { profile, kundli, loading, error } = useKundli(Number(id));
  const { t, lang } = useI18n();
  const [period, setPeriod] = useState<Period>("daily");
  const [cfg, setCfg] = useState<AiConfig | null>(null);
  const [usage, setUsage] = useState<UsageSummary | null>(null);
  const [aiText, setAiText] = useState<{ text: string; provider: string; costUsd: number } | null>(null);
  const [aiBusy, setAiBusy] = useState(false);
  const [aiNotice, setAiNotice] = useState("");

  const prediction: Prediction | null = useMemo(() => {
    if (!kundli) return null;
    if (period === "daily") return dailyPrediction(kundli);
    if (period === "weekly") return weeklyPrediction(kundli);
    if (period === "monthly") return monthlyPrediction(kundli);
    return yearlyPrediction(kundli);
  }, [kundli, period]);

  useEffect(() => {
    getAiConfig().then(setCfg);
    getUsageSummary().then(setUsage);
  }, []);

  // Reset AI insight when switching period
  useEffect(() => {
    setAiText(null);
    setAiNotice("");
  }, [period]);

  const canUseAi = cfg !== null && cfg.mode !== "never" && aiAvailable(cfg);
  const quotaExhausted =
    cfg !== null && usage !== null && usage.geminiRemaining <= 0 && !cfg.serverClaude;

  const fetchAiInsight = useCallback(async () => {
    if (!kundli || !prediction || !cfg || aiBusy) return;
    setAiBusy(true);
    setAiNotice("");
    const periodLabel = { daily: "today", weekly: "this week", monthly: "this month", yearly: "the coming year" }[prediction.period];
    const question = `Give a detailed, completely unbiased ${prediction.period} prediction for ${periodLabel}. Cover career, wealth, health and relationships. List BOTH the positive and the negative influences with equal weight — do not hide or soften any adverse indication.`;
    const result = await callAi(question, kundli, lang, cfg);
    setAiBusy(false);
    getUsageSummary().then(setUsage);
    if (typeof result === "string") {
      setAiNotice(result === "quota-exhausted" ? t("aiQuotaExhausted") : t("aiUnavailable"));
      return;
    }
    setAiText({ text: result.answer, provider: result.provider, costUsd: result.costUsd });
  }, [kundli, prediction, cfg, aiBusy, lang, t]);

  // AI mode "always": fetch the insight automatically (once per period view)
  useEffect(() => {
    if (cfg?.mode === "always" && canUseAi && !aiText && !aiBusy && prediction && navigator.onLine) {
      void fetchAiInsight();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cfg, period, prediction]);

  if (loading) return <AppShell><p className="p-8 text-center text-(--color-ink-soft)">{t("loading")}</p></AppShell>;
  if (error || !kundli || !profile || !prediction) {
    return (
      <AppShell>
        <div className="card mx-auto max-w-md p-8 text-center">
          <p className="text-red-300">{error ?? t("error")}</p>
          <Link href="/" className="accent-text mt-4 inline-block text-sm underline">← {t("dashboard")}</Link>
        </div>
      </AppShell>
    );
  }

  const pick = (b: { en: string; hi: string }) => (lang === "hi" ? b.hi : b.en);
  const toneCls = {
    good: "border-emerald-500/30",
    mixed: "border-(--color-line)",
    caution: "border-orange-500/40",
  };

  const areaEntries = [
    [t("career"), prediction.areas.career],
    [t("wealth"), prediction.areas.wealth],
    [t("health"), prediction.areas.health],
    [t("relationships"), prediction.areas.relationships],
  ] as const;

  return (
    <ProfileTheme birthdayNumber={kundli.numerology.birthdayNumber}>
      <AppShell>
        <div className="mb-5 flex flex-wrap items-center justify-between gap-3">
          <div>
            <h1 className="text-xl font-semibold text-(--color-gold-soft)">
              {t("predictionFor")} {profile.name}
            </h1>
            <p className="text-xs text-(--color-ink-soft)">
              {fmtDate(prediction.rangeStart, lang)} — {fmtDate(prediction.rangeEnd, lang)} · ✓ {t("generatedOffline")}
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            {/* AI usage meter */}
            {cfg && usage && cfg.mode !== "never" && (
              <Link
                href="/settings"
                className={`rounded-full border px-3 py-1 text-xs ${
                  quotaExhausted
                    ? "border-red-500/50 text-red-300"
                    : "border-(--color-line) text-(--color-ink-soft)"
                }`}
                title={t("quotaNote")}
              >
                ✨ {usage.geminiRemaining}/{GEMINI_FREE_RPD} {t("freeCallsLeft")}
                {usage.costTodayUsd > 0 ? ` · ${fmtCost(usage.costTodayUsd)}` : ""}
              </Link>
            )}
            <div className="flex gap-1 rounded-lg border border-(--color-line) p-1 text-sm">
              {(["daily", "weekly", "monthly", "yearly"] as const).map((p) => (
                <button
                  key={p}
                  onClick={() => setPeriod(p)}
                  className={`rounded-md px-3 py-1.5 transition ${
                    period === p ? "accent-bg accent-text font-medium" : "text-(--color-ink-soft)"
                  }`}
                >
                  {t(p)}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="card accent-border mb-5 border-l-4 p-5">
          <p className="leading-relaxed">{pick(prediction.summary)}</p>
        </div>

        {/* AI Insight — primary reading (auto-loads in Always mode) */}
        {cfg && cfg.mode !== "never" && (
          <div className="card mb-5 border-l-4 border-violet-500/40 p-5">
            <div className="flex flex-wrap items-center justify-between gap-2">
              <h3 className="text-sm font-medium text-violet-300">
                {t("aiInsight")}
                {aiText && ` · ${aiText.provider} · ${aiText.costUsd === 0 ? t("free") : fmtCost(aiText.costUsd)}`}
              </h3>
              {!aiText && !aiBusy && canUseAi && (
                <button
                  onClick={fetchAiInsight}
                  disabled={quotaExhausted}
                  className="rounded-lg border border-violet-500/40 px-4 py-2 text-sm text-violet-300 transition hover:bg-violet-500/10 disabled:opacity-50"
                  title={quotaExhausted ? t("aiQuotaExhausted") : undefined}
                >
                  {t("getAiInsight")}
                </button>
              )}
            </div>
            {aiBusy && <p className="mt-2 text-sm text-(--color-ink-soft)">✨ {t("aiThinking")}</p>}
            {aiNotice && <p className="mt-2 text-sm text-orange-300">{aiNotice}</p>}
            {!canUseAi && !aiText && (
              <p className="mt-2 text-xs text-(--color-ink-soft)">{t("aiNotConfigured")}</p>
            )}
            {aiText && (
              <p className="mt-3 whitespace-pre-wrap text-sm leading-relaxed">{aiText.text}</p>
            )}
          </div>
        )}

        {/* Area meters */}
        <div className="mb-5 grid grid-cols-2 gap-3 md:grid-cols-4">
          {areaEntries.map(([label, score]) => (
            <div key={label} className="card p-4">
              <div className="flex items-baseline justify-between">
                <span className="text-sm text-(--color-ink-soft)">{label}</span>
                <span className="text-lg font-semibold accent-text">{score}</span>
              </div>
              <div className="mt-2 h-1.5 overflow-hidden rounded-full bg-(--color-surface)">
                <div
                  className="h-full rounded-full"
                  style={{
                    width: `${score}%`,
                    background: score >= 58 ? "#4ade80" : score >= 48 ? "#fbbf24" : "#f87171",
                  }}
                />
              </div>
            </div>
          ))}
        </div>

        {period === "weekly" && (prediction.favourableDays?.length || prediction.cautionDays?.length) ? (
          <div className="mb-5 grid gap-3 md:grid-cols-2">
            {prediction.favourableDays && prediction.favourableDays.length > 0 && (
              <div className="card border-l-4 border-emerald-500/40 p-4">
                <h4 className="mb-1 text-sm font-medium text-emerald-300">{t("favourableDays")}</h4>
                <p className="text-sm">{prediction.favourableDays.join(" · ")}</p>
              </div>
            )}
            {prediction.cautionDays && prediction.cautionDays.length > 0 && (
              <div className="card border-l-4 border-orange-500/40 p-4">
                <h4 className="mb-1 text-sm font-medium text-orange-300">{t("cautionDays")}</h4>
                <p className="text-sm">{prediction.cautionDays.join(" · ")}</p>
              </div>
            )}
          </div>
        ) : null}

        <div className="space-y-3">
          {prediction.sections.map((s, i) => (
            <div key={i} className={`card border-l-4 p-5 ${toneCls[s.tone]}`}>
              <h3 className="mb-1 text-sm font-medium text-(--color-gold-soft)">{pick(s.title)}</h3>
              <p className="text-sm leading-relaxed">{pick(s.body)}</p>
            </div>
          ))}
        </div>

      </AppShell>
    </ProfileTheme>
  );
}
